var e=[{id:`L2_1`,type:`dialog`,speaker:`ZENZIROU_NANA_NULL_NULL`,text:{KOREA:`큭……!`,JPN:`くっ……！`,ENG:`Khhk!`,TWN:`唔……！`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_HATE`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`마사키! 괜찮아?`,JPN:`雅紀！　大丈夫か？`,ENG:`Masaki! Are you okay?`,TWN:`雅紀！你還好嗎？`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L4_1`,type:`dialog`,speaker:`ZENZIROU_NANA_NULL_NULL`,text:{KOREA:`끈질기군. 내 전력의 50%가 담긴 플레임 드라이브를 맞고도 아직 움직일 수 있다니.`,JPN:`しぶといやつだな。オレ様の力の50％を注ぎ込んだフレイムドライブを食らってもまだ動けるとは。`,ENG:`It’s so persistent. That Flame Drive had 50% of my normal power output, yet it’s still up.`,TWN:`你還真是頑強，被我50%戰力的驅動火焰打到竟然還能動？！`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L7_1`,type:`dialog`,speaker:`AKI_FREEDOM_NULL_NULL`,text:{KOREA:`히익……!`,JPN:`ひいっ……！`,ENG:`Eeep!`,TWN:`嗚嗚……！`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`AKI_FREEDOM_NULL_NULL`,text:{KOREA:`저리 가!`,JPN:`近づかないで！`,ENG:`Go away!`,TWN:`走開！`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:null,R:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L14_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`괜찮아, 아키?`,JPN:`大丈夫か、秋？`,ENG:`Are you okay, Aki?`,TWN:`廣瀨秋，你還好嗎？`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`AKI_FREEDOM_NULL_NULL`,text:{KOREA:`미나토 씨…`,JPN:`湊さん……`,ENG:`Minato...`,TWN:`南裕夏…`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`지금까지 잘해주고 있어! 조금만 더 버텨 줘!`,JPN:`よく頑張ってくれてるよ！　もう少しだけ耐えてくれ！`,ENG:`You’re doing fine! Just hold on a little longer!`,TWN:`目前為止你都做得很好！ 再堅持一下！`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`AKI_FREEDOM_NULL_NULL`,text:{KOREA:`무거워……. 칼이 너무 무겁다고요.`,JPN:`重い……剣が重すぎます。`,ENG:`It’s heavy... The sword is too heavy.`,TWN:`好重……這把劍好重。`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`AKI_FREEDOM_NULL_NULL`,text:{KOREA:`나 같은 겁쟁이가 이런 걸 감당할 수 있을 리 없잖아요.`,JPN:`秋みたいな臆病者にこんなこと、耐えられるわけないじゃないですか。`,ENG:`I’m too much of a coward to do something like this.`,TWN:`像我這種膽小鬼，怎麼可能承受得起這樣的重擔！`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`히로세 씨…? 울어요?`,JPN:`廣瀬さん……？　泣いてるんですか？`,ENG:`Ms. Hirose? Are you crying?`,TWN:`廣瀨秋…？你在哭喔？`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`AKI_FREEDOM_NULL_NULL`,text:{KOREA:`미, 민서 씨?!`,JPN:`……ヒ、ヒミコさん！`,ENG:`M-Minseo?`,TWN:`旼…旼序？！`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`지금 이게 어떻게 된 상황이죠?`,JPN:`これはどういう状況ですか？`,ENG:`What’s going on?`,TWN:`現在是什麼情況？`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L25_1`,type:`dialog`,speaker:`AKI_FREEDOM_NULL_NULL`,text:{KOREA:`어떻게 되긴요! 민서가 기절하는 바람에 도망도 못 가고 발이 묶여 있는 거죠!`,JPN:`どういう状況だなんて！　ヒミコさんが気絶したせいで逃げることもできず、ここで足止めされているんですよ！`,ENG:`What do you think? I failed to run because you fainted!`,TWN:`你還敢問什麼情況！都是因為你昏過去，害我們被困在這裡逃不了！`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L26_1`,type:`dialog`,speaker:`LEEMINSEO_FREEDOM_NULL_NULL`,text:{KOREA:`시체… 시체는 어떻게 된 거예요?`,JPN:`死体……死体はどうなったんですか？`,ENG:`The dead body... What happened to the body?`,TWN:`屍體…怎麼會有屍體？`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:{char_id:`AKI_FREEDOM_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`LEEMINSEO_FREEDOM_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L28_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`아키! 오른쪽에서 오는 침식체들을 부탁해!`,JPN:`秋！　右側から来る侵食体たちを頼む！`,ENG:`Aki! Take care of the C.O.s from the right side!`,TWN:`廣瀨秋！從右邊來的侵蝕體就交給你囉！`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};